import java.util.Arrays;

public int maximumUnits(int[][] boxTypes, int truckSize) {
    Arrays.sort(boxTypes, (a, b) -> b[1] - a[1]);

    int totalUnits = 0;
    for (int[] box : boxTypes) {
        int boxCount = Math.min(truckSize, box[0]);
        totalUnits += boxCount * box[1];
        truckSize -= boxCount;
        if (truckSize == 0) {
            break;
        }
    }

    return totalUnits;
}
```

